+            json!({
+                "target_bucket": target_bucket,
+                "flat_slot_pages": cache.flat_slots.len(),
+                "overflow_pages": overflow_pages,
+                "probe_window_limit": MAX_PROBE_LENGTH
+            }),
+        );
